4	const BASE_PRICE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function singleItemPremium(item: { type: string }): number {
13	  const base = BASE_PRICE[item.type];
14	  return base + base * FIRST_INSURANCE_RATE;
15	}
16	
17	function itemPremium(items: { type: string }[]): number {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] || 0) + 1;
21	  }
22	
23	  let totalBase = 0;
24	  for (const type in counts) {
25	    const count = counts[type];
26	    if (count === 3) {
27	      totalBase += 60;
28	    } else {
29	      totalBase += count * BASE_PRICE[type];
30	    }
31	  }
32	
33	  return totalBase + totalBase * FIRST_INSURANCE_RATE;
34	}
